WITH exam_stats AS (SELECT exam_id, MAX(score) AS max_s, MIN(score) AS min_s FROM Exam GROUP BY exam_id)
SELECT DISTINCT s.student_id, s.student_name FROM Student s JOIN Exam e ON s.student_id = e.student_id
WHERE s.student_id NOT IN (
  SELECT e2.student_id FROM Exam e2 JOIN exam_stats es ON e2.exam_id = es.exam_id
  WHERE e2.score = es.max_s OR e2.score = es.min_s
) ORDER BY s.student_id;
